INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["門","家","地"],"answer":"大","position":"prefix","explanation":"可組成:大門、大家、大地。","_meta":{"diversity":8,"commonness":10,"rationale":"大門、大家(眾人/世家)、大地語意多元且常見"},"definitions":{"大門":"較大的門；特指建築物中對外的正門。","大家":"指某一群體內的人。;有顯著成就的專家。;有名望的世族。;〈書〉對女子的尊稱。","大地":"廣闊的地面。;指地球。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["光","重","正"],"answer":"大","position":"suffix","explanation":"可組成:光大、重大、正大。","_meta":{"diversity":8,"commonness":8,"rationale":"光大發揚、重大形容、正大品德,意義差異明顯"},"definitions":{"光大":"發展使更加興盛。","重大":"（事情或責任）大而重要。","正大":"（言行）正當；不偏不邪。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["地","中","分"],"answer":"心","position":"suffix","explanation":"可組成:地心、中心、分心。","_meta":{"diversity":9,"commonness":9,"rationale":"地心、中心、分心皆常用且意義差異大"},"definitions":{"地心":"地球的中心點。","中心":"與四周距離相等的位置；物體的正中央。;核心；事物的主體，最為重要的部分。;泛指某一占有樞紐地位的地點或機構。","分心":"分散心思、注意力。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["人","打","下"],"answer":"手","position":"suffix","explanation":"可組成:人手、打手、下手。","_meta":{"diversity":8,"commonness":9,"rationale":"人手=人力、打手=幫凶、下手=動手,語義差異大"},"definitions":{"人手":"每人手上；每人手裡。;做事的人。","打手":"受僱替人打架或恐嚇他人的人。","下手":"出手；動手；著手；採取行動。;（按尊卑排座位時）居於下方或後面的位置。也作「下首」。;助手；幫手。;打牌、遊戲或行酒令時，下一個輪到的人。也作「下家」、「下首」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["水","打","生"],"answer":"手","position":"suffix","explanation":"可組成:水手、打手、生手。","_meta":{"diversity":8,"commonness":8,"rationale":"水手職業、打手暴力、生手新手,三義鮮明"},"definitions":{"水手":"船員的技術職稱之一，在船面擔任操舵、帶纜、消防、堵漏、保養、維修等工作。;泛指駕船的人。","打手":"受僱替人打架或恐嚇他人的人。","生手":"對所做工作或某項技術還不熟悉的人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["分","名","長"],"answer":"學","position":"prefix","explanation":"可組成:學分、學名、學長。","_meta":{"diversity":8,"commonness":9,"rationale":"學分=制度、學名=正式名稱、學長=人,語意分歧大"},"definitions":{"學分":"量詞。用於計算學科分量。通常以一學期每週上課一節課（一小時）為一學分。","學名":"舊稱兒童入學時取的正式名字。;科學上為求統一與便於研究、學習，所定的專門名稱。如酒精的學名為乙醇。","學長":"對高年級或年長同學的尊稱。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["分","海","年"],"answer":"學","position":"prefix","explanation":"可組成:學分、學海、學年。","_meta":{"diversity":8,"commonness":9,"rationale":"學分=制度、學海=比喻、學年=時間,差異明顯"},"definitions":{"學分":"量詞。用於計算學科分量。通常以一學期每週上課一節課（一小時）為一學分。","學海":"指學問匯集之處或學術界。;〈書〉指做學問當如河川流向大海，日進不已。","學年":"學校的教學年度。大多數從秋季開學到次年暑假。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["小","文","開"],"answer":"學","position":"suffix","explanation":"可組成:小學、文學、開學。","_meta":{"diversity":8,"commonness":10,"rationale":"三詞皆常用,小學=學校、文學=學問、開學=動詞,角色多元"},"definitions":{"小學":"正規教育中最初階的學校。在學年齡為6歲－12歲，是國民教育的第一階段，主要培養學童的國家及民族意識、倫理道德、健全體格及基本生活知能。臺⃝也作「國民小學」、「國小」。;研究文字字形、字音、字義的學問。包括文字學、聲韻學及訓詁學。","文學":"以語言文字為工具，形象化地反映社會生活的藝術，包括詩歌、散文、小說、戲劇等。","開學":"新學期開始。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["風","門","道"],"answer":"家","position":"prefix","explanation":"可組成:家風、家門、家道。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞皆常用且家字意涵多元"},"definitions":{"家風":"家族世代相承的風氣或傳統。","家門":"住家大門；借指自己的家。;家庭；家族。;門第；家族的名聲。;指個人的家世、經歷等。","家道":"家中的經濟狀況。;家庭運道。;〈書〉治家的規範。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["書","小","法"],"answer":"家","position":"prefix","explanation":"可組成:家書、家小、家法。","_meta":{"diversity":8,"commonness":8,"rationale":"三詞常用,家字意義有別"},"definitions":{"家書":"家人間往來的書信。也作「家信」。","家小":"指妻子及兒女。;特指妻子。","家法":"〈書〉古代師徒相承，自成一家的學術理論及治學方法。後泛指學術、文藝相傳的流派或風格。;治家的法規、準則。;指處罰家人的刑具。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["道","事","中"],"answer":"國","position":"prefix","explanation":"可組成:國道、國事、國中。","_meta":{"diversity":8,"commonness":9,"rationale":"國道(道路)、國事(事務)、國中(學制)語法角色不同"},"definitions":{"國道":"由國家統一規劃、修建和管理的國有道路。","國事":"國家的政務大事。","國中":"國民中學的簡稱。國民義務教育的第二階段學校。年滿12歲的少年都須入學，修業時間為3年。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["家","事","小"],"answer":"國","position":"prefix","explanation":"可組成:國家、國事、國小。","_meta":{"diversity":8,"commonness":10,"rationale":"國家、國事、國小三詞皆常用,意義有別"},"definitions":{"國家":"具有領土、人民、主權、政府的組合團體。","國事":"國家的政務大事。","國小":"國民小學的簡稱。正規教育中最初階的學校。在學年齡為6歲－12歲，是國民教育的第一階段，主要培養學童的國家及民族意識、倫理道德、健全體格及基本生活知能。也作「小學」。陸⃝即「小學」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["開","公","出"],"answer":"國","position":"suffix","explanation":"可組成:開國、公國、出國。","_meta":{"diversity":8,"commonness":9,"rationale":"開國=建國、公國=國體、出國=離開國境,意義差異大"},"definitions":{"開國":"建立國家政權。","公國":"指歐洲封建時代的諸侯國家，以公爵為國家元首；現今的公國多為君主立憲制國家。","出國":"到國外去。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["長","流","工"],"answer":"車","position":"prefix","explanation":"可組成:車長、車流、車工。","_meta":{"diversity":8,"commonness":8,"rationale":"車長人員、車流現象、車工職業,角色多元"},"definitions":{"車長":"車輛自車頭至車尾的長度。;火車、高鐵等客運列車上負責查票、聯絡及安全相關事務的人。","車流":"像流水般連續不斷行駛的車輛。","車工":"使用車床或機器進行的工作和技術。;使用車床工作的工人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["開","國","酒"],"answer":"花","position":"suffix","explanation":"可組成:開花、國花、酒花。","_meta":{"diversity":8,"commonness":8,"rationale":"開花、國花、酒花皆常見且意義不同"},"definitions":{"開花":"花朵綻放。;比喻像花朵那樣綻裂。;比喻十分高興，露出滿面笑容。;陸⃝比喻經驗傳開或事業發展、興盛。","國花":"象徵一個國家的花朵。可顯示該國的民族特性與精神。","酒花":"植物名。多年生草本。蔓生，莖葉有短刺。葉具長柄，對生，先端銳尖。果穗球果狀，有揮發油和苦味素，多用於製作啤酒，使具有香味和苦味。可入藥，具健胃、利尿等功效。也作「忽布」、「蛇麻」、「啤酒花」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["開","名","落"],"answer":"花","position":"suffix","explanation":"可組成:開花、名花、落花。","_meta":{"diversity":8,"commonness":9,"rationale":"開花、名花、落花皆熟詞,語法角色各異"},"definitions":{"開花":"花朵綻放。;比喻像花朵那樣綻裂。;比喻十分高興，露出滿面笑容。;陸⃝比喻經驗傳開或事業發展、興盛。","名花":"名貴的花。;比喻有名的美女。","落花":"凋落的花瓣。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["木","民","藥"],"answer":"草","position":"prefix","explanation":"可組成:草木、草民、草藥。","_meta":{"diversity":8,"commonness":8,"rationale":"草木、草民、草藥意義各異"},"definitions":{"草木":"花草樹木。","草民":"賤稱百姓或平民自稱。","草藥":"以植物為原料的中藥藥材。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["大","下","門"],"answer":"風","position":"suffix","explanation":"可組成:大風、下風、門風。","_meta":{"diversity":8,"commonness":8,"rationale":"大風自然、下風方位/劣勢、門風家聲,意義分歧大"},"definitions":{"大風":"很大的風。;強勁的風。氣象學風級表的第八級風。","下風":"風吹往的方向。;比喻作戰或比賽時處於不利的地位。亦引申為自謙之詞。","門風":"指一家、一族世代傳承的道德風尚和處世原則。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["子","氣","下"],"answer":"天","position":"prefix","explanation":"可組成:天子、天氣、天下。","_meta":{"diversity":8,"commonness":9,"rationale":"天子(帝王)、天氣(氣候)、天下(世界),三義差異大且皆常見"},"definitions":{"天子":"帝王。古人認為帝王受命於天，為天之子，故稱。","天氣":"在一定時間和空間內大氣發生的各種氣象變化。;時候；時間。","天下":"古時指中國境內的全部；全國。;指全世界。;指國家或國家的統治權。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["口","馬","面"],"answer":"海","position":"prefix","explanation":"可組成:海口、海馬、海面。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,海口比喻、海馬生物、海面地理意涵不同"},"definitions":{"海口":"河流入海的地方。;海灣內的港口。;大話。","海馬":"魚名。體長與體色變化很大，體表有骨質化之鱗片，頭部像馬頭，尾細長，生活在海洋中。種類很多，晒乾後可用於中藥。","海面":"海水的表面。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["口","流","外"],"answer":"海","position":"prefix","explanation":"可組成:海口、海流、海外。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞皆常用,海口、海流、海外語意角色各異"},"definitions":{"海口":"河流入海的地方。;海灣內的港口。;大話。","海流":"海洋中具有一定路線的水流。也作「洋流」。;泛指流動的海水。","海外":"國外。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["公","出","學"],"answer":"海","position":"suffix","explanation":"可組成:公海、出海、學海。","_meta":{"diversity":9,"commonness":9,"rationale":"三詞皆熟悉,海義多元"},"definitions":{"公海":"主權不屬於任何國家，即不在任何國家管轄範圍之內的海域。","出海":"（駕駛或乘坐船舶）離開港口或其他停泊地點，到海上去。","學海":"指學問匯集之處或學術界。;〈書〉指做學問當如河川流向大海，日進不已。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["法","火","公"],"answer":"海","position":"suffix","explanation":"可組成:法海、火海、公海。","_meta":{"diversity":8,"commonness":8,"rationale":"法海為人名但常見,三詞海義不同"},"definitions":{"法海":"話本〈白娘子永鎮雷峰塔〉、小說及民間故事《白蛇傳》中的人物。以法缽收服白蛇精，鎮於雷峰塔下。一說人物原型即金山寺法海，史料記載其曾驅趕咬傷人獸的白色蟒蛇入長江。;唐代高僧的法號。生卒年、生平均不詳，約唐睿宗至玄宗時，韶州（今廣東）曲江人。《…","火海":"大片的火；大火。;比喻極其危險的境地。","公海":"主權不屬於任何國家，即不在任何國家管轄範圍之內的海域。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["氣","同","寒"],"answer":"窗","position":"suffix","explanation":"可組成:氣窗、同窗、寒窗。","_meta":{"diversity":8,"commonness":8,"rationale":"氣窗為實體、同窗指同學、寒窗喻苦讀,意義差異大"},"definitions":{"氣窗":"開在牆壁上部或屋頂，主要用於流通空氣的窗子。","同窗":"同學。也作「同硯」。","寒窗":"比喻艱苦的讀書生活。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["門","寒","鐵"],"answer":"窗","position":"suffix","explanation":"可組成:門窗、寒窗、鐵窗。","_meta":{"diversity":8,"commonness":8,"rationale":"門窗實體、寒窗苦讀、鐵窗監獄,意義差異大"},"definitions":{"門窗":"門和窗的合稱。","寒窗":"比喻艱苦的讀書生活。","鐵窗":"裝上鐵柵的窗戶。;特指監獄。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["子","車","光"],"answer":"電","position":"prefix","explanation":"可組成:電子、電車、電光。","_meta":{"diversity":8,"commonness":9,"rationale":"電子、電車、電光皆常用,語意分屬粒子、交通、光線"},"definitions":{"電子":"構成原子的基本粒子之一。帶負電，質量極小，圍繞帶正電的原子核分布。電子的定向運動形成電流。","電車":"用電作動力的公共交通車輛。分有軌和無軌兩種。","電光":"電能發出的光；特指雷電的光。;織物經特殊處理後所獲得的一種耀眼光澤。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["手","官","中"],"answer":"高","position":"prefix","explanation":"可組成:高手、高官、高中。","_meta":{"diversity":8,"commonness":9,"rationale":"高手能人、高官職位、高中學校或考中,語義多元"},"definitions":{"高手":"能力、本領特別強的人。","高官":"高級官員。","高中":"高級中學的簡稱：;臺⃝介於國民中學與大專院校之間的學校。以培養學生研究高深學術及學習專門知識的基本能力，奠定其接受高等教育的基礎。;陸⃝實施普通中等教育後一階段教育的學校。;高分通過考試。多用於祝賀人通過考試。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["學","身","年"],"answer":"長","position":"suffix","explanation":"可組成:學長、身長、年長。","_meta":{"diversity":8,"commonness":9,"rationale":"學長為稱謂、身長為高度、年長為形容詞,意義分明"},"definitions":{"學長":"對高年級或年長同學的尊稱。","身長":"人體的高度。;裁縫業指上衣從肩到下擺的長度。","年長":"年歲大。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["明","眼","自"],"answer":"白","position":"suffix","explanation":"可組成:明白、眼白、自白。","_meta":{"diversity":8,"commonness":8,"rationale":"明白=清楚、眼白=眼球白處、自白=坦白,意思差異大"},"definitions":{"明白":"清楚；使人了解。;明確；公開。;懂得；知道。;懂事理、不糊塗。;醒悟；清醒。","眼白":"眼球最外層的纖維膜，白色而不透明，具有保護眼球內部組織、維持眼球形態等功用。也作「白眼珠」、「白眼球」、「鞏膜」。;〈書〉眼睛朝上或向旁邊看，顯出白眼珠，表示對人藐視或厭惡。也作「白眼」。","自白":"自我表白。;自我表白的話。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["抹","掃","摸"],"answer":"黑","position":"suffix","explanation":"可組成:抹黑、掃黑、摸黑。","_meta":{"diversity":8,"commonness":9,"rationale":"抹黑誣陷、掃黑掃蕩、摸黑趁暗,語意明顯不同"},"definitions":{"抹黑":"塗黑。比喻扭曲、醜化。","掃黑":"掃蕩、清除黑社會組織。陸⃝也作「打黑」。","摸黑":"〈口〉在黑暗中摸索著行動。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["子","天","手"],"answer":"老","position":"prefix","explanation":"可組成:老子、老天、老手。","_meta":{"diversity":9,"commonness":9,"rationale":"老子(自稱)、老天(天)、老手(熟練者)三者語義差異大"},"definitions":{"老子":"即李耳，生卒年不詳，字聃，一字伯陽，世稱「老子」、「老聃」，春秋楚國苦縣（今河南鹿邑東）人。先秦著名的思想家。曾任周朝守藏室之史（管理藏書的史官），相傳孔子曾向他問禮。主張無為，為道家始祖。著有《老子》。;書名。春秋‧老耳撰。分上下兩篇，闡…","老天":"對主宰宇宙萬物的神的俗稱。;表示祈求或驚歎的用語。∥也作「老天爺」。","老手":"指在某一方面富有經驗的人。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["土","田","素"],"answer":"雞","position":"suffix","explanation":"可組成:土雞、田雞、素雞。","_meta":{"diversity":9,"commonness":8,"rationale":"土雞為禽、田雞為蛙、素雞為豆製品,意義差異大"},"definitions":{"土雞":"放養於山間野外，不以人工飼料飼養的雞種。","田雞":"兩棲動物名。青蛙的別稱。泛指無尾的兩棲動物，頭大嘴闊，兩眼凸出，黃綠色並帶有灰色斑紋者為多，趾間有蹼，善跳躍，會游泳，雄蛙鳴聲響亮。生活在水中或水邊，捕食昆蟲，有益農業。","素雞":"一種豆製品。用豆腐皮紮緊加工製成，可以切碎與其他食品混合烹調燒製，也可以單獨涼拌成菜。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["草","黃","木"],"answer":"魚","position":"suffix","explanation":"可組成:草魚、黃魚、木魚。","_meta":{"diversity":8,"commonness":8,"rationale":"草魚、黃魚、木魚都熟悉,木魚意義特殊(法器)"},"definitions":{"草魚":"魚名。體略呈紡錘形，前端圓筒狀，青黃色。棲息於湖泊、河川或水庫，取食水草為主。生長快速，體長可達1.5公尺，是重要的淡水養殖食用魚。也作「鯇」、「草鰱」。","黃魚":"魚名。頭大體略側扁，尾狹窄，體側上半黃褐色，下半金黃色。分大黃魚和小黃魚。主要分布在大陸沿海，近年來因過度捕撈而資源衰退。","木魚":"一種佛教的法器。以木頭製成，空心。相傳魚晝夜不合目，故刻木像魚形以示晝夜思道之意。僧侶念經或化緣時敲打的木器，也作為打擊樂器使用。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["落","化","結"],"answer":"石","position":"suffix","explanation":"可組成:落石、化石、結石。","_meta":{"diversity":8,"commonness":8,"rationale":"落石、化石、結石都是常見詞,意涵各異"},"definitions":{"落石":"（從高處）掉落或滾落的石頭。","化石":"埋藏在地層已石質化的古生物遺骸、遺蹟或人類遺物、遺蹟。是鑑定地層年代、地殼變化、生物演化和考古學研究的珍貴資料。","結石":"個體的某些空腔器官及其導管內，由於有機物或無機鹽的沉積而結成的堅硬物質。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["重","合","黃"],"answer":"金","position":"suffix","explanation":"可組成:重金、合金、黃金。","_meta":{"diversity":8,"commonness":9,"rationale":"重金(貴重)、合金(混合金屬)、黃金(顏色/金屬)三詞常見且意義各異"},"definitions":{"重金":"巨額錢款。","合金":"一種金屬元素與其他金屬或非金屬元素鎔合而成的物質。","黃金":"稀有、珍貴的金屬之一。質地軟、易延展，可打成金箔。色澤黃、抗腐蝕，黃金色澤歷久不變。熔點高、比重大，容易分辨。一般用來製造貨幣和裝飾品。通稱「金子」。;寶貴的；完美的。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["面","色","本"],"answer":"腳","position":"prefix","explanation":"可組成:腳面、腳色、腳本。","_meta":{"diversity":8,"commonness":8,"rationale":"腳面身體、腳色角色、腳本劇本,意義多元且常用"},"definitions":{"腳面":"腳掌的背面。也作「腳背」。","腳色":"演員所扮演的劇中人物。;比喻社會生活中某一類型的人物。∥也作「角色」。","腳本":"戲劇、曲藝演出或電影、電視攝製等所依據的底本。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["風","門","家"],"answer":"口","position":"suffix","explanation":"可組成:風口、門口、家口。","_meta":{"diversity":8,"commonness":8,"rationale":"風口、門口、家口都常見,語義各異"},"definitions":{"風口":"因兩旁高起而使風力集中、風速增大的地方。如山口、街口、樓口等。;比喻情況激烈、形勢不利。","門口":"門的出入口。","家口":"家庭中的人口。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["下","花","色"],"answer":"眼","position":"prefix","explanation":"可組成:眼下、眼花、眼色。","_meta":{"diversity":8,"commonness":8,"rationale":"眼下時間、眼花狀態、眼色暗示,三者分歧"},"definitions":{"眼下":"目前。","眼花":"眼睛昏花，看東西模糊不清。","眼色":"示意或傳情的目光。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["體","乾","票"],"answer":"肉","position":"prefix","explanation":"可組成:肉體、肉乾、肉票。","_meta":{"diversity":8,"commonness":8,"rationale":"肉體=身體、肉乾=食物、肉票=人質,語義差異大"},"definitions":{"肉體":"指人的身體。","肉乾":"將精肉經滷製、烘乾等程序脫去多數水分所製成的食品。保存期限較之常溫下放置的鮮肉長。","肉票":"被綁匪劫持的人質。綁匪藉以向其親屬勒索財物。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["心","家","分"],"answer":"身","position":"prefix","explanation":"可組成:身心、身家、身分。","_meta":{"diversity":8,"commonness":9,"rationale":"三詞常用,身=內外/家境/個人身分差異大"},"definitions":{"身心":"身體和精神。","身家":"自身及家庭。;家庭背景；出身。;財產；家庭資財。","身分":"個人在社會上或法律上擔任的角色、地位。;符合所處社會地位的修養；受尊敬的地位。∥也作「身份」。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["分","一","出"],"answer":"身","position":"suffix","explanation":"可組成:分身、一身、出身。","_meta":{"diversity":8,"commonness":8,"rationale":"分身=另一個自己、一身=全身、出身=來歷,差異大"},"definitions":{"分身":"抽出時間或精力去處理另外的事物。;臺⃝指神像的分靈。","一身":"一人。;渾身；全身。","出身":"指個人根據前段經歷或因家庭背景而具備的身分。;舊時稱科舉考試中舉者的身分。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["盤","斷","品"],"answer":"果","position":"prefix","explanation":"可組成:果盤、果斷、果品。","_meta":{"diversity":8,"commonness":8,"rationale":"果盤(器物)、果斷(形容詞)、果品(總稱)差異大且常見"},"definitions":{"果盤":"盛放果品的盤子。","果斷":"果敢決斷；毫不遲疑。","果品":"水果及乾果的統稱。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["太","胞","辣"],"answer":"妹","position":"suffix","explanation":"可組成:太妹、胞妹、辣妹。","_meta":{"diversity":8,"commonness":8,"rationale":"太妹、胞妹、辣妹皆熟悉,妹意涵差異大"},"definitions":{"太妹":"俗稱品德不良，行為放蕩不端的少女。","胞妹":"同父母所生的妹妹。","辣妹":"穿著打扮新潮時髦，作風豪放的年輕女性。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["聽","簡","改"],"answer":"寫","position":"suffix","explanation":"可組成:聽寫、簡寫、改寫。","_meta":{"diversity":8,"commonness":9,"rationale":"聽簡改寫三義不同且常用"},"definitions":{"聽寫":"聽和寫；也指將聽到的內容書寫下來。常用於語文教學練習或測驗。","簡寫":"用簡體寫法寫（漢字）。如把「體」簡寫為「体」。;漢字的簡體寫法。如「气」是「氣」的簡寫。","改寫":"（將原先的作品、文稿等）修改或部分重寫。;比喻重新締造或創造。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["物","具","味"],"answer":"玩","position":"prefix","explanation":"可組成:玩物、玩具、玩味。","_meta":{"diversity":8,"commonness":9,"rationale":"玩物物品、玩具器物、玩味品味,語意角色不同"},"definitions":{"玩物":"沉溺於所喜好的事物。;用作玩賞的東西。;比喻不受尊重、被當作玩賞物品的人。","玩具":"專供遊戲玩樂的東西。","玩味":"反覆研習，仔細體味。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["票","味","賞"],"answer":"玩","position":"prefix","explanation":"可組成:玩票、玩味、玩賞。","_meta":{"diversity":8,"commonness":8,"rationale":"玩票業餘、玩味品味、玩賞欣賞,意義差異大"},"definitions":{"玩票":"業餘的人參加戲曲演出。;比喻做非本職的工作。∥陸⃝也作「玩兒票」。","玩味":"反覆研習，仔細體味。","玩賞":"觀賞；玩弄欣賞。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["遊","童","賞"],"answer":"玩","position":"suffix","explanation":"可組成:遊玩、童玩、賞玩。","_meta":{"diversity":8,"commonness":8,"rationale":"遊玩童玩賞玩皆常見,玩字義差異明顯"},"definitions":{"遊玩":"遊戲玩耍；遊覽玩賞。","童玩":"孩童的玩具。如毽子、扯鈴、風箏等。","賞玩":"觀賞玩味。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["重","主","點"],"answer":"唱","position":"suffix","explanation":"可組成:重唱、主唱、點唱。","_meta":{"diversity":8,"commonness":9,"rationale":"重唱主唱點唱皆熟悉,角色形式皆異"},"definitions":{"重唱":"一種演唱形式，由兩個或兩個以上的歌手各按不同的聲部配合演唱同一首歌曲。可分為二重唱、三重唱、四重唱等。;重新演唱。","主唱":"在樂團擔任主要演唱的人；也指電影、電視劇中唱主題曲、片頭曲、片尾曲的人。","點唱":"指定表演的人唱某首歌或某段戲曲。"}}');
INSERT INTO questions (type, difficulty, payload) VALUES ('zizhu', 'elementary', '{"hints":["意","力","戰"],"answer":"筆","position":"prefix","explanation":"可組成:筆意、筆力、筆戰。","_meta":{"diversity":8,"commonness":8,"rationale":"筆意、筆力、筆戰皆熟悉,意義有別:意境、力道、論戰"},"definitions":{"筆意":"字畫、詩文等表現出來的情趣或意境。","筆力":"書法、繪畫或寫作等在筆法上表現出來的氣勢和力量。;寫作能力。","筆戰":"指書面論爭。也作「筆仗」。;〈書〉執筆的手顫抖。"}}');
